import base64, tarfile, io, os

DATA = """"""

# Decode and extract
archive = base64.b64decode(DATA)
with tarfile.open(fileobj=io.BytesIO(archive), mode="r:gz") as tar:
    tar.extractall(".")
    names = tar.getnames()
    for n in names:
        print(f"  Extracted: {n}")
print(f"Unpacked {len(names)} files.")
